    public void DepositClicked()
    {
        if (PlayerPrefs.GetString("NewChain") == "1")
        {


            whatDeposit = CryptoDepositHistory._Instance.cryptoDeposit.options[CryptoDepositHistory._Instance.cryptoDeposit.value].text;
        }

        if (PlayerPrefs.GetString("NewChain") == "56")
        {


            whatDeposit = CryptoDepositHistory._Instance.cryptoDepositBEP.options[CryptoDepositHistory._Instance.cryptoDepositBEP.value].text;
        }
        if (PlayerPrefs.GetString("NewChain") == "89")
        {


            whatDeposit = CryptoDepositHistory._Instance.cryptoDepositMATIC.options[CryptoDepositHistory._Instance.cryptoDepositMATIC.value].text;
        }
        if (whatDeposit == "MATIC")
        {
            OnDepositMatic();
        }
        if (whatDeposit == "USDT")
        {
            OnSendApproveTETHER();
        }
        if (whatDeposit == "USDC")
        {
            OnSendApproveUSDC();
        }
        if (whatDeposit == "LINK")
        {
            OnSendApproveLINK();
        }
        if (whatDeposit == "FDUSD")
        {
            OnSendApproveFDUSD();
        }
        if (whatDeposit == "CRO")
        {
            OnSendApproveCRO();
        }
        if (whatDeposit == "SHIB")
        {
            OnSendApproveSHIB();
        }
        if (whatDeposit == "APE")
        {
            OnSendApproveAPE();
        }
    }

